// spellPower = baseSpellPower + floor×spellPowerPerFloor + level×spellPowerPerLevel
// Sorcerer: 10 + 0×floor + 7×level
// L0=10, L5=45, L10=80, L15=115
// Deep-floor bonus: passivePerLevel.spellPower = 10 per level above 10
// L15 with passives: 115 + (15-10)×10 = 165

// Warrior:  50 + level×5  (L10=100; passivePerLevel.mana=0, no late bonus)
// Rogue:    60 + level×6  (L10=120; passivePerLevel.mana=0)
// Sorcerer: 60 + level×6  (L10=120; passivePerLevel.mana=8/level above L10)
// Sorcerer L15: 120 + (15-10)×8 = 160 mana
